            holder.btnDownload.text = "..."
            holder.btnDownload.isEnabled = false
        }
        onDownload(build, exists) 
    }
    } else if (holder is FooterViewHolder) {
        holder.btnLoadMore.setOnClickListener {
            holder.btnLoadMore.text = "Loading..."
            onLoadMore()
        }
    }
}

override fun getItemCount(): Int {
    return if (canLoadMore) builds.size + 1 else builds.size
}

fun updateList(newBuilds: List<BuildStatus>, repo: String) {
    builds.clear()
    builds.addAll(newBuilds)
    currentRepo = repo
    canLoadMore = newBuilds.size >= 20
    notifyDataSetChanged()
}

fun addMore(moreBuilds: List<BuildStatus>) {
    val start = builds.size
    builds.addAll(moreBuilds)
    canLoadMore = moreBuilds.size >= 20
    notifyItemRangeInserted(start, moreBuilds.size)
    notifyItemChanged(builds.size) // Refresh footer
}

